import '../App.js'
import '../App.css';


import React, { Component, useState } from 'react';
// import Product  from './Product.js';

function Cart(props) {
   const [quentity,setQuentity]=useState(1)
   const [currPrice,setCurrPrice]=useState(props.CartPrice);
   const [updatedPrice]=useState(props.CartPrice)
   
const plus=()=>{
   setQuentity(quentity+1);
   setCurrPrice(currPrice+updatedPrice)
}
const minus=()=>{
   if(quentity>1){
      setQuentity(quentity-1);
      setCurrPrice(currPrice-updatedPrice)
   }
   else{
      alert("sorry")
   }
  
}

  return (
  
 <div className='cart'>
 <div className='d-flex justify-content-around align-items-center'>
   
<img src={props.CartImg} alt="" className="w-25"/>
   <div className=''>{currPrice}</div>
   <div className='cart-btn d-flex gap-2'>
<div className='cart-minus'>
<button onClick={minus}>-</button>
</div>
<p className='mb-0'>
{quentity}
</p>
<div className='cart-plus'>
<button onClick={plus}>+</button>

</div>
   </div>
 
   
 </div>
 <div className='remove-item'>
  <h5 className='mb-0'>total price : {
    currPrice.map((item)=>{
      return(
      item.price
      )
    }).reduce((currValue,updatedValue)=>(currValue+updatedValue),0)
  }</h5>
 
   </div>
</div>
  );
}

export default Cart;
